#!/usr/bin/env python3
"""Find GO development terms that should classify under GO:0160108 but don't."""

import re
import sys
from collections import defaultdict

def parse_obo(path):
    """Parse OBO file, return list of stanzas as dicts."""
    stanzas = []
    cur = None
    with open(path) as f:
        for line in f:
            line = line.rstrip('\n')
            if line.startswith('[Term]') or line.startswith('[Typedef]'):
                if cur is not None:
                    stanzas.append(cur)
                cur = {'_type': line.strip('[]'), '_lines': []}
            elif line == '' or not line.strip():
                continue
            elif cur is None:
                continue
            else:
                cur['_lines'].append(line)
                if ':' in line:
                    key, _, val = line.partition(': ')
                    cur.setdefault(key, []).append(val)
    if cur is not None:
        stanzas.append(cur)
    return stanzas

def get_id(s):
    return s.get('id', [None])[0]

def is_obsolete(s):
    return s.get('is_obsolete', ['false'])[0] == 'true'

def name(s):
    return s.get('name', [None])[0]

print("Parsing edit obo...", file=sys.stderr)
edit_stanzas = parse_obo('/__w/go-ontology/go-ontology/src/ontology/go-edit.obo')

print("Parsing reasoned obo...", file=sys.stderr)
reas_stanzas = parse_obo('/tmp/go-edit.reasoned.obo')

# Build is_a graph from reasoned ontology, then compute descendants
# For each term: collect is_a parents
parents = defaultdict(set)  # child -> set of parents
for s in reas_stanzas:
    if s['_type'] != 'Term':
        continue
    if is_obsolete(s):
        continue
    cid = get_id(s)
    if cid is None:
        continue
    for ia in s.get('is_a', []):
        pid = ia.split(' ')[0]
        parents[cid].add(pid)

# Compute ancestors via BFS
def ancestors(cid):
    seen = set()
    stack = list(parents.get(cid, set()))
    while stack:
        p = stack.pop()
        if p in seen:
            continue
        seen.add(p)
        stack.extend(parents.get(p, set()))
    return seen

# For each term in edit obo, check if it is a descendant of GO:0048856 and/or GO:0160108
GO_ASD = 'GO:0048856'  # anatomical structure development
GO_AGAPDP = 'GO:0160108'  # animal gross anatomical part developmental process
GO_DEV = 'GO:0032502'  # developmental process

# Iterate over all GO terms in edit obo, check membership using reasoned ancestors
desc_asd = set()
desc_agapdp = set()
desc_dev = set()

# Note: a term T is descendant of X iff X in ancestors(T)
for s in edit_stanzas:
    if s['_type'] != 'Term':
        continue
    if is_obsolete(s):
        continue
    cid = get_id(s)
    if not cid or not cid.startswith('GO:'):
        continue
    a = ancestors(cid)
    if GO_ASD in a:
        desc_asd.add(cid)
    if GO_AGAPDP in a:
        desc_agapdp.add(cid)
    if GO_DEV in a:
        desc_dev.add(cid)

print(f"Descendants of GO:0032502 (developmental process): {len(desc_dev)}", file=sys.stderr)
print(f"Descendants of GO:0048856 (anatomical structure development): {len(desc_asd)}", file=sys.stderr)
print(f"Descendants of GO:0160108 (animal gross anatomical part dev process): {len(desc_agapdp)}", file=sys.stderr)

# Look at: under GO:0048856 but NOT under GO:0160108 -- these are candidate terms
gap = desc_asd - desc_agapdp - {GO_AGAPDP, 'GO:0160109'}  # exclude the sibling animal/plant terms themselves
print(f"\nUnder GO:0048856 but NOT under GO:0160108: {len(gap)}", file=sys.stderr)

# Map edit stanzas by ID
edit_by_id = {}
for s in edit_stanzas:
    if s['_type'] != 'Term':
        continue
    cid = get_id(s)
    if cid:
        edit_by_id[cid] = s

# For each gap term, get the differentia
print("\n## GAP TERMS (under anatomical structure dev but not animal gross anatomical part dev)\n")
gap_by_target_ont = defaultdict(list)
gap_no_ld = []
for cid in sorted(gap):
    s = edit_by_id.get(cid, {})
    nm = name(s) or '?'
    # Look for intersection_of: results_in_development_of <ID>
    rido_target = None
    intersections = s.get('intersection_of', [])
    has_genus = False
    for inter in intersections:
        if inter.startswith(GO_ASD):
            has_genus = True
        elif inter.startswith('results_in_development_of '):
            rido_target = inter.split(' ')[1]
        elif inter.startswith('GO:'):
            has_genus = True
    if rido_target is None:
        gap_no_ld.append((cid, nm, intersections))
    else:
        ont_pfx = rido_target.split(':')[0]
        gap_by_target_ont[ont_pfx].append((cid, nm, rido_target))

print(f"\n### Terms with no `results_in_development_of` differentia: {len(gap_no_ld)}\n")
for cid, nm, intersections in gap_no_ld[:100]:
    print(f"  {cid}  {nm}")
    if intersections:
        for i in intersections:
            print(f"      intersection_of: {i}")

print("\n### Terms with results_in_development_of by target ontology:\n")
for ont, lst in sorted(gap_by_target_ont.items(), key=lambda x: -len(x[1])):
    print(f"\n  --- {ont} ({len(lst)}) ---")
    for cid, nm, target in lst[:30]:
        print(f"  {cid}  {nm}    -> {target}")

