                    'UBERON:0005162',  # multi cell part structure
                    'UBERON:0034713',  # cranial neuron projection bundle
                    'UBERON:0001021',  # nerve
                ):
                    top_parents.append(p)
            key = ','.join(sorted(top_parents)) if top_parents else 'UNKNOWN'
            ub_gap_by_parent[key].append(
                (cid, nm, rido_target, ub_names.get(rido_target, '?'))
            )
    else:
        ont = rido_target.split(':')[0]
        non_uberon[ont].append((cid, nm, rido_target))

